SELECT device_id, device_name
FROM devices
WHERE status = 'active' AND device_type = 'camera';

external_knowledge:
- 'developers' refers to users with the role name 'developer';
- 'sailing in the New York harbor' metaphorically refers to users who are active or performing actions in the New York location;
- 'capturing images with their cameras' denotes that the device type involved in these actions is 'camera'.

